    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #2c2d30;
    flex-shrink: 0;
}

.thread-header h4 {
    margin: 0;
    font-size: 1rem;
    color: #fff;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    color: #9b9b9b;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
}

.close-btn:hover {
    background: #2c2d30;
    color: #fff;
}

.thread-root-quote {
    padding: 12px 16px;
    border-bottom: 1px solid #2c2d30;
    background: #222529;
    flex-shrink: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 16px;
}
